// @ts-check

import { AbstractHandler } from './AbstractHandler.js'
import { Command } from '../../utils/Command.js'
import { CommandType } from '../../utils/CommandType.js'
import { RuntimeName } from '../../utils/RuntimeName.js'

export class RetrieveArrayHandler extends AbstractHandler {
    requiredParametersCount = 1

    /**
     * @param {unknown} value
     * @returns {value is ArrayLike<any>}
     */
    isArrayLike(value) {
        return (
            typeof value === 'object' &&
            value !== null &&
            'length' in value &&
            typeof value.length === 'number'
        )
    }

    /**
     * @param {any} command
     */
    process(command) {
        this.validate(command, this.requiredParametersCount, this.constructor.name)

        let payloadValue = command.payload[0]

        if (payloadValue instanceof ArrayBuffer) {
            payloadValue = Array.from(new Uint8Array(payloadValue))
        } else if (typeof SharedArrayBuffer !== 'undefined' && payloadValue instanceof SharedArrayBuffer) {
            payloadValue = Array.from(new Uint8Array(payloadValue))
        } else if (ArrayBuffer.isView(payloadValue)) {
            if (payloadValue instanceof DataView) {
                payloadValue = Array.from(
                    new Uint8Array(payloadValue.buffer, payloadValue.byteOffset, payloadValue.byteLength)
                )
            } else if (this.isArrayLike(payloadValue)) {
                payloadValue = Array.from(payloadValue)
            }
        }

        if (Array.isArray(payloadValue)) {
            return new Command(RuntimeName.Nodejs, CommandType.Array, payloadValue)
        }

        throw new Error('Invalid argument type for RetrieveArrayHandler. Expected an array.')
    }
}
